class Board:
    def __init__(self):
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        self.board = [[None] * 8 for _ in range(8)]
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'black')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'white')

    def display_board(self):
        # Display the board
        print("   A B C D E F G H")
        for i, row in enumerate(self.board):
            print(f"{i + 1}  " + " ".join(p.char if p else '.' for p in row))

    def is_valid_move(self, start, end):
        # Check if the move is valid
        piece = self.get_piece(start)
        if not piece:
            return False
        if piece.color != self.current_player and self.current_player == 'black':
            return False
        if piece.color != self.current_player and self.current_player == 'white':
            return False

        # Simple move or jump
        if end in self.get_possible_moves(start):
            return True
        else:
            return False

    def get_piece(self, position):
        # Get the piece at a given position
        col = ord(position[0]) - ord('A')
        row = int(position[1]) - 1
        return self.board[row][col]

    def get_possible_moves(self, start):
        # Get all possible moves from a starting position
        piece = self.get_piece(start)
        if not piece:
            return []

        moves = []
        for move in self.get_simple_moves(start) + self.get_jumps(start):
            moves.append(move)
        return moves

    def get_simple_moves(self, start):
        # Get all simple moves from a starting position
        col = ord(start[0]) - ord('A')
        row = int(start[1]) - 1
        moves = []
        if piece.color == 'black':
            if self.board[row + 1][col - 1] is None:
                moves.append((chr(col - 1 + ord('A')) + str(row + 2)))
            if col < 6 and self.board[row + 1][col + 1] is None:
                moves.append((chr(col + 1 + ord('A')) + str(row + 2)))
        elif piece.color == 'white':
            if row > 0 and col > 0 and self.board[row - 1][col - 1] is None:
                moves.append((chr(col - 1 + ord('A')) + str(row)))
            if row > 0 and col < 6 and self.board[row - 1][col + 1] is None:
                moves.append((chr(col + 1 + ord('A')) + str(row)))
        return moves

    def get_jumps(self, start):
        # Get all jump moves from a starting position
        col = ord(start[0]) - ord('A')
        row = int(start[1]) - 1
        jumps = []
        if piece.color == 'black':
            if row < 6 and col > 1 and self.board[row + 2][col - 2] is None and self.board[row + 1][col - 1] != None:
                jumps.append((chr(col - 2 + ord('A')) + str(row + 3)))
            if row < 6 and col < 5 and self.board[row + 2][col + 2] is None and self.board[row + 1][col + 1] != None:
                jumps.append((chr(col + 2 + ord('A')) + str(row + 3)))
        elif piece.color == 'white':
            if row > 1 and col > 0 and self.board[row - 2][col - 2] is None and self.board[row - 1][col - 1] != None:
                jumps.append((chr(col - 2 + ord('A')) + str(row)))
            if row > 1 and col < 5 and self.board[row - 2][col + 2] is None and self.board[row - 1][col + 1] != None:
                jumps.append((chr(col + 2 + ord('A')) + str(row)))
        return jumps

    def make_move(self, start, end):
        # Make a move on the board
        col = ord(start[0]) - ord('A')
        row = int(start[1]) - 1
        piece = self.board[row][col]
        self.board[row][col] = None
        end_col = ord(end[0]) - ord('A')
        end_row = int(end[1]) - 1
        self.board[end_row][end_col] = Piece(end_row, end_col, piece.color)

    def change_turn(self):
        # Change the turn
        if self.current_player == 'black':
            self.current_player = 'white'
        else:
            self.current_player = 'black'

    def check_game_over(self):
        # Check if the game is over
        black_pieces = sum(row.count('black') for row in self.board)
        white_pieces = sum(row.count('white') for row in self.board)
        return black_pieces == 0 or white_pieces == 0
